INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('员工关系专员 - 上海（社招）', '互联网 / IT', '上海', '民营企业', 10000, 15000, '1. 熟悉人事事务性工作的流程和处理方法；2. 熟练使用Office办公软件', '工作细心、谨慎，优秀的沟通能力；良好的团队协作能力，能与各部门同事愉快协作；稳定的情绪管控能力', 0, '一般', '1. 负责员工入转调离手续办理及合同档案管理；2. 负责员工落户积分办理；3. 负责员工考勤管理；4. 负责每月员工的工资数据核算及申请；5. 负责新员工入职培训', '员工关系支持、薪酬绩效支持', '大专及以上', '无强制专业限制', '3-5年，三年以上员工关系工作经验，须有电商直播行业经验', '社招（应届生可投）', '有电商直播行业员工关系管理经验；有人力资源管理师相关证书', '10k-15k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系专员 - 潍坊（社招）', '其他', '潍坊', '民营企业', 4000, 6000, '1. 熟悉劳动法规；2. 熟练使用Office办公软件', '细心负责，沟通协调能力强；逻辑清晰、抗压性好', 1, '友好', '1. 负责员工入离职、劳动合同、人事档案管理；2. 处理员工关系事宜，营造和谐职场氛围；3. 组织员工活动，协助企业文化落地；4. 对接员工咨询，保障制度合规执行', '员工关系支持、OD 组织发展支持', '大专及以上', '无强制专业限制', '经验不限，有人事/员工关系相关经验优先', '社招（应届生可投）', '有人力资源相关证书；有员工关系相关工作经验', '4k-6k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('人事专员（员工关系） - 深圳（社招）', '其他', '深圳', '民营企业', 6000, 8000, '1. 熟悉员工关系板块工作，熟悉《劳动合同法》及地方性法律法规（如入离职风险把控、五险一金/假期/节假日规则等基础性知识）；2. 熟练使用办公软件', '对工作有规划和目标，学习能力和适应能力强，具有良好的沟通能力和抗压精神', 0, '一般', '1. 负责员工的入转调离工作；2. 负责客户/员工的需求及时沟通和处理；3. 负责部门内部其他协调性工作（员工档案更新维护/信息同步等）', '员工关系支持', '大专及以上', '无强制专业限制', '1-3年，一年及以上人力资源相关工作经验', '社招（应届生可投）', '有人力资源管理师相关证书；有大型企业人事专员工作经验', '6k-8k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('员工关系专员 - 厦门（社招）', '制造', '厦门', '民营企业', 7000, 10000, '熟练使用Office办公软件', '有较强的责任心和严谨细致的工作态度；具备良好的沟通能力与团队协作意识；能够适应较长时间的事务性工作，具有耐心与稳定性', 0, '一般', '1. 负责员工入离职、在职期间劳动关系的协调与管理；2. 协助处理员工考勤、薪酬相关事务及劳动保障事务；3. 参与劳动关系制度的优化与执行推进；4. 配合完成劳动纠纷处理及相关事务性工作', '员工关系支持、薪酬绩效支持', '大专及以上', '无强制专业限制', '3-5年相关工作经验', '社招（应届生可投）', '有人力资源管理师相关证书；有劳动纠纷处理相关经验', '7k-10k/月', '46112', NULL, 'BOSS直聘平台获取', '员工关系类', '甲方（企业自有 HR 岗）'), ('行政专员 - 桂林（社招）', '其他', '桂林', '民营企业', 3000, 5000, '具备行政相关知识，能够独立处理行政相关工作；熟练使用Office办公软件', '具有良好的沟通能力和团队合作精神，能够与各部门有效协调；注重细节，具备较强的组织和解决问题的能力', 1, '友好', '1. 负责公司行政前台相关工作，包括但不限于行政日常工作，固定资产盘点、手机、账号、会议管理等；2. 协助处理行政相关的日常事务，确保部门运作顺畅', '行政事务支持、固定资产管理、会议活动组织', '大专及以上', '无强制专业限制', '1-3年，有大型活动策划经验的优先', '社招（应届生可投）', '有大型活动策划经验；有行政相关证书', '3k-5k/月', '46112', NULL, 'BOSS直聘平台获取', '行政类', '甲方（企业自有 HR 岗）');